import { describe, it, expect } from 'vitest';
import { crossModalSigmaScore } from '../src/cross-modal-moonshine';

describe('crossModalSigmaScore', () => {
  it('perfectly synchronized sequences give max agreement and sigma === baseSigma', () => {
    const visual = new Float32Array([0, 1, 0, 1, 0]);
    const audio = new Float32Array([0, 1, 0, 1, 0]);
    const baseSigma = 1.5;
    const report = crossModalSigmaScore({
      visual,
      audio,
      baseSigma,
      adjustmentStrength: 0.5,
    });

    expect(report.sigmaPerFrame).toHaveLength(5);
    // Frame 0 always baseSigma.
    expect(report.sigmaPerFrame[0]).toBeCloseTo(baseSigma, 6);
    // All other frames: dV === dA after normalization, so agreement = 1, sigma = baseSigma.
    for (let t = 1; t < 5; t++) {
      expect(report.agreementPerFrame[t]).toBeCloseTo(1, 6);
      expect(report.sigmaPerFrame[t]).toBeCloseTo(baseSigma, 6);
    }
    expect(report.meanAgreement).toBeCloseTo(1, 6);
  });

  it('anti-correlated sequences give low agreement on the disagreeing frames', () => {
    // Single visual transient at frame 1, single audio transient at frame 4.
    const visual = new Float32Array([0, 1, 1, 1, 1]);
    const audio = new Float32Array([0, 0, 0, 0, 1]);
    const baseSigma = 2.0;
    const adjustmentStrength = 0.5;
    const report = crossModalSigmaScore({
      visual,
      audio,
      baseSigma,
      adjustmentStrength,
    });

    // Frame 1: dV normalized = 1, dA normalized = 0 → agreement = 0, sigma = baseSigma * 1.5.
    expect(report.agreementPerFrame[1]).toBeCloseTo(0, 6);
    expect(report.sigmaPerFrame[1]).toBeCloseTo(baseSigma * (1 + adjustmentStrength * 1), 6);
    // Frame 4: dV normalized = 0, dA normalized = 1 → agreement = 0, sigma boosted.
    expect(report.agreementPerFrame[4]).toBeCloseTo(0, 6);
    expect(report.sigmaPerFrame[4]).toBeCloseTo(baseSigma * (1 + adjustmentStrength * 1), 6);
    // Frames 2 and 3 have zero deltas on both sides → agreement = 1.
    expect(report.agreementPerFrame[2]).toBeCloseTo(1, 6);
    expect(report.agreementPerFrame[3]).toBeCloseTo(1, 6);
  });

  it('heartbeat counts split into waste / opportunity / diversity and sum to n', () => {
    // Frame 1: visual changes alone (waste / lighting transient).
    // Frame 4: audio changes alone (opportunity / motion blur).
    // Frame 0: always diversity (no deltas).
    // Frames 2, 3: both still → diversity.
    const visual = new Float32Array([0, 1, 1, 1, 1]);
    const audio = new Float32Array([0, 0, 0, 0, 1]);
    const report = crossModalSigmaScore({
      visual,
      audio,
      baseSigma: 1,
      adjustmentStrength: 0.5,
    });

    expect(report.heartbeat.waste).toBe(1);
    expect(report.heartbeat.opportunity).toBe(1);
    expect(report.heartbeat.diversity).toBe(3);
    const total =
      report.heartbeat.waste +
      report.heartbeat.opportunity +
      report.heartbeat.diversity;
    expect(total).toBe(visual.length);
  });

  it('validation: mismatched lengths throws', () => {
    const visual = new Float32Array([0, 1, 2]);
    const audio = new Float32Array([0, 1]);
    expect(() =>
      crossModalSigmaScore({ visual, audio, baseSigma: 1 }),
    ).toThrow(RangeError);
  });

  it('validation: n < 2 throws', () => {
    const visual = new Float32Array([0]);
    const audio = new Float32Array([0]);
    expect(() =>
      crossModalSigmaScore({ visual, audio, baseSigma: 1 }),
    ).toThrow(RangeError);
  });

  it('validation: baseSigma <= 0 throws', () => {
    const visual = new Float32Array([0, 1]);
    const audio = new Float32Array([0, 1]);
    expect(() =>
      crossModalSigmaScore({ visual, audio, baseSigma: 0 }),
    ).toThrow(RangeError);
    expect(() =>
      crossModalSigmaScore({ visual, audio, baseSigma: -0.1 }),
    ).toThrow(RangeError);
  });

  it('validation: adjustmentStrength out of [0, 1] throws', () => {
    const visual = new Float32Array([0, 1]);
    const audio = new Float32Array([0, 1]);
    expect(() =>
      crossModalSigmaScore({
        visual,
        audio,
        baseSigma: 1,
        adjustmentStrength: -0.01,
      }),
    ).toThrow(RangeError);
    expect(() =>
      crossModalSigmaScore({
        visual,
        audio,
        baseSigma: 1,
        adjustmentStrength: 1.5,
      }),
    ).toThrow(RangeError);
  });

  it('adjustmentStrength = 0 returns baseSigma always, regardless of disagreement', () => {
    const visual = new Float32Array([0, 1, 1, 1, 1]);
    const audio = new Float32Array([0, 0, 0, 0, 1]);
    const baseSigma = 3.14;
    const report = crossModalSigmaScore({
      visual,
      audio,
      baseSigma,
      adjustmentStrength: 0,
    });
    for (let t = 0; t < visual.length; t++) {
      expect(report.sigmaPerFrame[t]).toBeCloseTo(baseSigma, 6);
    }
  });

  it('first frame is always baseSigma regardless of the rest', () => {
    const visual = new Float32Array([10, 0, 1, 2, 3]);
    const audio = new Float32Array([0, 5, 4, 3, 2]);
    const baseSigma = 0.7;
    const report = crossModalSigmaScore({
      visual,
      audio,
      baseSigma,
      adjustmentStrength: 1,
    });
    expect(report.sigmaPerFrame[0]).toBeCloseTo(baseSigma, 6);
    expect(report.agreementPerFrame[0]).toBeCloseTo(0, 6);
  });

  it('range bound: sigmaPerFrame[t] in [baseSigma, baseSigma * (1 + adjustmentStrength)]', () => {
    // Mixed disagreement fixture.
    const visual = new Float32Array([0, 1, 1, 0.5, 0.5]);
    const audio = new Float32Array([0, 0, 0.5, 0.5, 1]);
    const baseSigma = 2.0;
    const adjustmentStrength = 0.7;
    const report = crossModalSigmaScore({
      visual,
      audio,
      baseSigma,
      adjustmentStrength,
    });
    const lo = baseSigma;
    const hi = baseSigma * (1 + adjustmentStrength);
    for (let t = 0; t < visual.length; t++) {
      expect(report.sigmaPerFrame[t]).toBeGreaterThanOrEqual(lo - 1e-6);
      expect(report.sigmaPerFrame[t]).toBeLessThanOrEqual(hi + 1e-6);
    }
    // And agreement is in [0, 1] for t >= 1.
    for (let t = 1; t < visual.length; t++) {
      expect(report.agreementPerFrame[t]).toBeGreaterThanOrEqual(0 - 1e-6);
      expect(report.agreementPerFrame[t]).toBeLessThanOrEqual(1 + 1e-6);
    }
  });
});
